+	namespace := c.Params("namespace")
+	name := c.Params("name")
+
+	imports, err := h.k8sClient.ListServiceImportsForCluster(c.Context(), cluster, namespace)
+	if err != nil {
+		return c.Status(500).JSON(fiber.Map{"error": err.Error()})
